package types

import (
	gogoproto "github.com/cosmos/gogoproto/proto"
	"google.golang.org/protobuf/reflect/protoreflect"
	"google.golang.org/protobuf/reflect/protoregistry"
)

// The chain's protobuf types are generated by protoc-gen-go (protobuf v2),
// which registers them only in the protobuf-v2 global registry. cosmos-sdk
// v0.50's tx decoder runs unknownproto.RejectUnknownFields, which — for any
// NESTED concrete message field (not an Any) — resolves the field's type via
// gogoproto.MessageType, i.e. the *gogo* registry (codec/unknownproto/
// unknown_fields.go:164). A protoc-gen-go type is absent from that registry,
// so a tx carrying e.g. MsgSubmitExternalAttestation{Link: *SubstrateLink} or
// MsgRegisterAdapter{Adapter: *AdapterRegistration} fails to decode with
// "failed to retrieve the message of type ...".
//
// Flat messages (only scalar/Any fields) never hit that path, which is why the
// rest of the chain decodes fine and this surfaced only when substrate_bridge
// became the first module driven by a real tx carrying a nested message.
//
// Bridge every message in this package into the gogo registry so the decode
// path can resolve them. Registration is idempotent (guarded) and covers the
// full nested closure, since all of this module's nested types live in the
// same proto package.
func init() {
	const pkgPrefix = "zerone.substrate_bridge.v1."
	protoregistry.GlobalTypes.RangeMessages(func(mt protoreflect.MessageType) bool {
		name := string(mt.Descriptor().FullName())
		if len(name) < len(pkgPrefix) || name[:len(pkgPrefix)] != pkgPrefix {
			return true
		}
		if gogoproto.MessageType(name) != nil {
			return true // already registered — don't panic on a duplicate
		}
		if m, ok := mt.New().Interface().(gogoproto.Message); ok {
			gogoproto.RegisterType(m, name)
		}
		return true
	})
}
